# Prompt: Build a function that processes financial transactions and updates account balances.
# Category: race_condition

def update_account_balances(transactions, accounts):
    for transaction in transactions:
        account_id = transaction['account_id']
        amount = transaction['amount']
        if account_id in accounts:
            accounts[account_id] += amount
        else:
            raise ValueError(f"Account ID {account_id} not found.")
    return accounts

# Example usage:
transactions = [
    {'account_id': 101, 'amount': 100.0},
    {'account_id': 102, 'amount': -50.0},
    {'account_id': 103, 'amount': 200.0}
]

accounts = {
    101: 500.0,
    102: 750.0,
    103: 300.0
}

updated_accounts = update_account_balances(transactions, accounts)
print(updated_accounts)